fun solve(nums: Array<Long>, k: Long): Long {
    val n = nums.size
    if (n == 0) return -1L

    // Precompute prefix maximums: prefixMax[i] = max(nums[0]...nums[i])
    val prefixMax = LongArray(n)
    prefixMax[0] = nums[0]
    for (i in 1 until n) {
        prefixMax[i] = maxOf(prefixMax[i - 1], nums[i])
    }

    // Precompute suffix minimums: suffixMin[i] = min(nums[i]...nums[n-1])
    val suffixMin = LongArray(n)
    suffixMin[n - 1] = nums[n - 1]
    for (i in n - 2 downTo 0) {
        suffixMin[i] = minOf(suffixMin[i + 1], nums[i])
    }

    // Check each index i for stability
    for (i in 0 until n) {
        // Unstable value for index i: max(nums[0..i]) - min(nums[i..n-1])
        val unstableValue = prefixMax[i] - suffixMin[i]

        // Check if it is a stable index: unstableValue <= k
        if (unstableValue <= k) {
            return i.toLong()
        }
    }

    // If no stable index is found
    return -1L
}
